const performance = $('Get Performance Card').first().json;

const prompt = `Write a YouTube community post summarizing this week's Bitcoin AI predictions. Data:

${JSON.stringify(performance, null, 2)}

Casual, visual-friendly (use emojis for data points). Ask viewers to comment their prediction. Mention @BTC_Seer_Bot on Telegram. Max 500 chars.`;

return [{ json: { prompt } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const text = $('Extract Response').first().json.text;
const now = new Date().toISOString();
console.log(`[${now}] YouTube community post: ${text.substring(0, 80)}...`);
console.log('NOTE: YouTube Community Posts API requires YouTube Studio access. This node uses commentThreads as a placeholder. For production, consider using YouTube Studio internal API or manual posting with the generated text.');
return [{ json: { status: 'posted', platform: 'youtube', timestamp: now, post_length: text.length, note: 'Uses commentThreads API as placeholder. YouTube Community Posts require YouTube Studio API access.' } }];
